#[cfg(not(windows))]
fn validate_file_security(
    path: &Path,
    label: &str,
    disallowed_mode_mask: u32,
    allow_root_owner: bool,
) -> Result<(), DaemonError> {
    validate_parent_directory_security(path, label, allow_root_owner)?;

    let link_metadata = fs::symlink_metadata(path).map_err(|err| {
        DaemonError::InvalidConfig(format!("{label} metadata read failed: {err}"))
    })?;
    if link_metadata.file_type().is_symlink() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} must not be a symlink"
        )));
    }
    if !link_metadata.file_type().is_file() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} must be a regular file"
        )));
    }

    let metadata = fs::metadata(path).map_err(|err| {
        DaemonError::InvalidConfig(format!("{label} metadata read failed: {err}"))
    })?;
    let mode = metadata.permissions().mode();
    if mode & disallowed_mode_mask != 0 {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} has insecure permissions: mode {:o}",
            mode & 0o777
        )));
    }

    let owner_uid = metadata.uid();
    let expected_uid = Uid::effective().as_raw();
    if owner_uid != expected_uid && !(allow_root_owner && owner_uid == 0) {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} owner uid mismatch: expected {expected_uid}, got {owner_uid}"
        )));
    }
    fs::File::open(path).map_err(|err| {
        DaemonError::InvalidConfig(format!(
            "{label} is not readable by runtime user (uid {expected_uid}): {err}"
        ))
    })?;
    Ok(())
}

#[cfg(windows)]
fn validate_file_security(
    path: &Path,
    label: &str,
    _disallowed_mode_mask: u32,
    _allow_root_owner: bool,
) -> Result<(), DaemonError> {
    validate_windows_runtime_file_path(path, label).map_err(DaemonError::InvalidConfig)?;
    let link_metadata = fs::symlink_metadata(path).map_err(|err| {
        DaemonError::InvalidConfig(format!("{label} metadata read failed: {err}"))
    })?;
    if link_metadata.file_type().is_symlink() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} must not be a symlink"
        )));
    }
    if !link_metadata.file_type().is_file() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} must be a regular file"
        )));
    }
    fs::File::open(path).map_err(|err| {
        DaemonError::InvalidConfig(format!(
            "{label} is not readable by the current service identity: {err}"
        ))
    })?;
    // Use local-secret ACL (not runtime ACL) so files created during SSH bootstrap
    // (owned by the admin SSH user, not SYSTEM/BA) are accepted. NTFS DACL on the
    // containing directory enforces access control; the file-owner SID is not a
    // meaningful security invariant — the directory-level owner check in
    // validate_windows_runtime_startup_acls() is the authoritative gate.
    validate_windows_local_secret_acl(path, label).map_err(DaemonError::InvalidConfig)
}

#[cfg(not(windows))]
fn validate_parent_directory_security(
    path: &Path,
    label: &str,
    allow_root_owner: bool,
) -> Result<(), DaemonError> {
    let parent = path.parent().ok_or_else(|| {
        DaemonError::InvalidConfig(format!(
            "{label} path must include a parent directory: {}",
            path.display()
        ))
    })?;
    let metadata = fs::symlink_metadata(parent).map_err(|err| {
        DaemonError::InvalidConfig(format!(
            "{label} parent directory metadata read failed for {}: {err}",
            parent.display()
        ))
    })?;
    if metadata.file_type().is_symlink() || !metadata.file_type().is_dir() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} parent directory must be a non-symlink directory: {}",
            parent.display()
        )));
    }

    let mode = metadata.permissions().mode() & 0o777;
    let owner_uid = metadata.uid();
    let owner_gid = metadata.gid();
    let expected_gid = Gid::effective().as_raw();
    let root_managed_shared_runtime =
        is_root_managed_shared_runtime_parent(parent, mode, owner_uid, owner_gid, expected_gid);

    if mode & 0o022 != 0 && !root_managed_shared_runtime {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} parent directory has insecure permissions: mode {mode:o}"
        )));
    }

    let expected_uid = Uid::effective().as_raw();
    if owner_uid != expected_uid
        && !(allow_root_owner && owner_uid == 0)
        && !root_managed_shared_runtime
    {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} parent directory owner uid mismatch: expected {expected_uid}, got {owner_uid}"
        )));
    }
    Ok(())
}

#[cfg(windows)]
fn validate_parent_directory_security(
    path: &Path,
    label: &str,
    _allow_root_owner: bool,
) -> Result<(), DaemonError> {
    let parent = path.parent().ok_or_else(|| {
        DaemonError::InvalidConfig(format!(
            "{label} path must include a parent directory: {}",
            path.display()
        ))
    })?;
    validate_windows_runtime_file_path(parent, label).map_err(DaemonError::InvalidConfig)?;
    let metadata = fs::symlink_metadata(parent).map_err(|err| {
        DaemonError::InvalidConfig(format!(
            "{label} parent directory metadata read failed for {}: {err}",
            parent.display()
        ))
    })?;
    if metadata.file_type().is_symlink() || !metadata.file_type().is_dir() {
        return Err(DaemonError::InvalidConfig(format!(
            "{label} parent directory must be a non-symlink directory: {}",
            parent.display()
        )));
    }
    validate_windows_runtime_acl(parent, label).map_err(DaemonError::InvalidConfig)
}

#[cfg(target_os = "linux")]
fn is_root_managed_shared_runtime_parent(
    parent: &Path,
    mode: u32,
    owner_uid: u32,
    owner_gid: u32,
    expected_gid: u32,
) -> bool {
    parent == Path::new("/run/rustynet")
        && owner_uid == 0
        && mode == 0o770
        && (owner_gid == expected_gid || owner_gid == 0)
}

/// Track B Phase 18 — macOS allowlist. The macOS install adapter
/// (`crates/rustynet-cli/src/vm_lab/orchestrator/adapter/macos_install.rs`)
/// creates `/private/var/run/rustynet` with mode 0o770 owned by
/// root and group `rustynetd` so the daemon (which runs as
/// rustynetd) can write its socket inside. Without this allowlist,
/// the CLI's parent-directory security preflight rejected the
/// directory as `insecure permissions: mode 770` and refused to
/// connect — even when the daemon was healthy. Mirrors the Linux
/// `/run/rustynet` allowlist semantics exactly.
#[cfg(target_os = "macos")]
fn is_root_managed_shared_runtime_parent(
    parent: &Path,
    mode: u32,
    owner_uid: u32,
    owner_gid: u32,
    expected_gid: u32,
) -> bool {
    parent == Path::new("/private/var/run/rustynet")
        && owner_uid == 0
        && mode == 0o770
        && (owner_gid == expected_gid || owner_gid == 0)
}

#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn is_root_managed_shared_runtime_parent(
    _parent: &Path,
    _mode: u32,
    _owner_uid: u32,
    _owner_gid: u32,
    _expected_gid: u32,
) -> bool {
    false
}

#[cfg(not(windows))]
fn read_command_envelope(stream: &UnixStream) -> Result<CommandEnvelope, String> {
    stream
        .set_read_timeout(Some(std::time::Duration::from_secs(5)))
        .map_err(|e| e.to_string())?;
    let reader = std::io::BufReader::new(stream);
    ipc_read_command_envelope(reader).map_err(|e| e.to_string())
}

#[cfg(not(windows))]
fn write_response(mut stream: UnixStream, response: IpcResponse) -> Result<(), String> {
    stream
        .write_all(format!("{}\n", response.to_wire()).as_bytes())
        .map_err(|err| format!("write failed: {err}"))
}

#[cfg(not(windows))]
fn socket_owner_uid(path: &Path) -> Result<u32, DaemonError> {
    let metadata = fs::metadata(path).map_err(|err| DaemonError::Io(err.to_string()))?;
    Ok(metadata.uid())
}

#[cfg(not(windows))]
fn peer_uid(stream: &UnixStream) -> Option<u32> {
    #[cfg(any(target_os = "linux", target_os = "android"))]
    {
        return getsockopt(stream, PeerCredentials)
            .ok()
            .map(|cred| cred.uid());
    }

    #[cfg(any(
        target_os = "macos",
        target_os = "ios",
        target_os = "tvos",
        target_os = "watchos",
        target_os = "visionos"
    ))]
    return getsockopt(stream, LocalPeerCred)
        .ok()
        .map(|cred| cred.uid());

    #[allow(unreachable_code)]
    None
}

#[cfg(any(target_os = "linux", target_os = "android"))]
fn peer_pid(stream: &UnixStream) -> Option<i32> {
    getsockopt(stream, PeerCredentials)
        .ok()
        .map(|cred| cred.pid())
}

#[cfg(not(windows))]
fn peer_gid(_stream: &UnixStream) -> Option<u32> {
    #[cfg(any(target_os = "linux", target_os = "android"))]
    {
        return getsockopt(_stream, PeerCredentials)
            .ok()
            .map(|cred| cred.gid());
    }

    #[cfg(any(
        target_os = "macos",
        target_os = "ios",
        target_os = "tvos",
        target_os = "watchos",
        target_os = "visionos"
    ))]
    return getsockopt(_stream, LocalPeerCred)
        .ok()
        .and_then(|cred| cred.groups().first().copied());

    #[allow(unreachable_code)]
    None
}

#[cfg(not(windows))]
fn peer_group_ids(stream: &UnixStream) -> Vec<u32> {
    #[cfg(any(target_os = "linux", target_os = "android"))]
    {
        let mut groups = Vec::new();
        if let Some(gid) = peer_gid(stream) {
            groups.push(gid);
        }
        if let Some(pid) = peer_pid(stream) {
            groups.extend(read_linux_peer_groups_from_proc(pid));
        }
        groups.sort_unstable();
        groups.dedup();
        return groups;
    }

    #[cfg(any(
        target_os = "macos",
        target_os = "ios",
        target_os = "tvos",
        target_os = "watchos",
        target_os = "visionos"
    ))]
    return getsockopt(stream, LocalPeerCred)
        .ok()
        .map(|cred| {
            let mut groups = cred.groups().to_vec();
            groups.sort_unstable();
            groups.dedup();
            groups
        })
        .unwrap_or_default();

    #[allow(unreachable_code)]
    Vec::new()
}

#[cfg(any(target_os = "linux", target_os = "android"))]
fn read_linux_peer_groups_from_proc(pid: i32) -> Vec<u32> {
    if pid <= 0 {
        return Vec::new();
    }
    let status_path = PathBuf::from("/proc").join(pid.to_string()).join("status");
    let Ok(body) = fs::read_to_string(status_path) else {
        return Vec::new();
    };
    body.lines()
        .find_map(|line| line.strip_prefix("Groups:"))
        .map(|groups| {
            groups
                .split_whitespace()
                .filter_map(|token| token.parse::<u32>().ok())
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

#[cfg(not(windows))]
const LOCAL_IPC_AUTHORIZED_GROUP_NAMES: &[&str] = &["rustynet", "rustynetd"];

#[cfg(not(windows))]
fn authorized_local_ipc_group_ids() -> Vec<u32> {
    let mut ids = LOCAL_IPC_AUTHORIZED_GROUP_NAMES
        .iter()
        .filter_map(|name| {
            Group::from_name(name)
                .ok()
                .flatten()
                .map(|group| group.gid.as_raw())
        })
        .collect::<Vec<_>>();
    ids.sort_unstable();
    ids.dedup();
    ids
}

#[cfg(not(windows))]
fn peer_in_authorized_local_ipc_group(
    peer_group_ids: &[u32],
    authorized_group_ids: &[u32],
) -> bool {
    !authorized_group_ids.is_empty()
        && peer_group_ids
            .iter()
            .any(|gid| authorized_group_ids.binary_search(gid).is_ok())
}

/// Outcome of [`authorize_local_peer`]: the peer cleared the local IPC
/// authorisation policy and the daemon may dispatch the command. The
/// `via` field records which authorisation arm fired so the audit log
/// can describe success in concrete terms.
#[cfg(not(windows))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct LocalPeerAuthorization {
    peer_uid: u32,
    via: LocalAuthVia,
}

#[cfg(not(windows))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum LocalAuthVia {
    Root,
    SocketOwnerUid,
    AuthorizedGroup,
}

#[cfg(not(windows))]
impl LocalAuthVia {
    fn as_str(self) -> &'static str {
        match self {
            LocalAuthVia::Root => "root_uid",
            LocalAuthVia::SocketOwnerUid => "socket_owner_uid",
            LocalAuthVia::AuthorizedGroup => "authorized_group",
        }
    }
}

/// Denial reason returned by [`authorize_local_peer`]. The struct
/// carries enough fixed-vocab metadata to render a precise audit log
/// line without leaking peer identity in a way that violates
/// retention/privacy policy: peer uid/gid are administrative metadata
/// that local-machine operators already have access to via `lsof` etc.
#[cfg(not(windows))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct LocalPeerDenial {
    peer_uid: Option<u32>,
    peer_gid: Option<u32>,
    reason: &'static str,
}

#[cfg(not(windows))]
impl LocalPeerDenial {
    fn uid_status(&self) -> String {
        match self.peer_uid {
            Some(uid) => format!("uid={uid}"),
            None => "uid=unavailable".to_owned(),
        }
    }

    fn gid_status(&self) -> String {
        match self.peer_gid {
            Some(gid) => format!("gid={gid}"),
            None => "gid=unavailable".to_owned(),
        }
    }
}

#[cfg(not(windows))]
fn local_peer_denial_audit_line(command_kind: &str, denial: &LocalPeerDenial) -> String {
    format!(
        "ipc_peer_cred_denied command={} {} {} reason={}",
        command_kind,
        denial.uid_status(),
        denial.gid_status(),
        denial.reason
    )
}

/// Single hardened call site for local IPC peer-credential
/// authorisation. The policy is uniform across every local command
/// (read AND mutating): a connecting peer must be uid 0 (root), the
/// uid that owns the daemon socket, a member of a reviewed RustyNet
/// local-control group (`rustynet` / `rustynetd`). Defense-in-depth:
/// the socket file is already mode `0o600` owned by the daemon uid in
/// a `0o700` parent directory, but a single misconfiguration must not
/// be enough to expose Status/Netcheck/DnsInspect to a foreign uid on
/// the same host. SecurityMinimumBar §3.6 requires the explicit
/// per-command auth gate independent of file permissions.
///
/// macOS / iOS / tvOS / watchOS / visionOS: `LocalPeerCred` exposes
/// the peer uid plus group list, so the reviewed-group arm works
/// without `/proc`.
#[cfg(not(windows))]
fn authorize_local_peer(
    stream: &UnixStream,
    socket_owner_uid: u32,
    _socket_path: &Path,
) -> Result<LocalPeerAuthorization, LocalPeerDenial> {
    let peer_uid = peer_uid(stream);
    let peer_gid = peer_gid(stream);
    let peer_group_ids = peer_group_ids(stream);
    let Some(uid_value) = peer_uid else {
        return Err(LocalPeerDenial {
            peer_uid,
            peer_gid,
            reason: "peer_uid_unavailable",
        });
    };

    if uid_value == 0 {
        return Ok(LocalPeerAuthorization {
            peer_uid: uid_value,
            via: LocalAuthVia::Root,
        });
    }
    if uid_value == socket_owner_uid {
        return Ok(LocalPeerAuthorization {
            peer_uid: uid_value,
            via: LocalAuthVia::SocketOwnerUid,
        });
    }
    let authorized_group_ids = authorized_local_ipc_group_ids();
    if peer_in_authorized_local_ipc_group(&peer_group_ids, &authorized_group_ids) {
        return Ok(LocalPeerAuthorization {
            peer_uid: uid_value,
            via: LocalAuthVia::AuthorizedGroup,
        });
    }

    Err(LocalPeerDenial {
        peer_uid,
        peer_gid,
        reason: "uid_and_gid_do_not_match_authorized_local_ipc_policy",
    })
}

fn unix_now() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs())
        .unwrap_or(0)
}

fn sanitize_netcheck_value(value: &str) -> String {
    value
        .chars()
        .map(|ch| match ch {
            'a'..='z' | 'A'..='Z' | '0'..='9' | '_' | '-' | ':' | '.' | '/' | '+' => ch,
            _ => '_',
        })
        .collect()
}

fn membership_directory_from_state(
    state: &MembershipState,
    local_node_id: &str,
) -> MembershipDirectory {
    let mut directory = MembershipDirectory::default();
    for node in &state.nodes {
        let status = match node.status {
            MembershipNodeStatus::Active => MembershipStatus::Active,
            MembershipNodeStatus::Revoked | MembershipNodeStatus::Quarantined => {
                MembershipStatus::Revoked
            }
        };
        directory.set_node_status(node.node_id.clone(), status);
    }
    directory.set_selector_members(DEFAULT_REMOTE_OPS_EXPECTED_SUBJECT, [local_node_id]);
    directory
}

/// D13: per-node overlay addresses from the verified assignment
/// bundle, for the `peers.v1` identity map the service binaries
/// resolve tunnel source addresses against. The bundle's peer
/// `allowed_ips` host CIDRs (`/32` / `/128`) are the daemon's only
/// signed per-node overlay-address source on the apply paths; the
/// first host entry per node wins (the assignment generator emits
/// exactly one). Non-host CIDRs (advertised routes) are skipped —
/// a route is not an identity.
fn overlay_addresses_from_bundle_peers(bundle: &AutoTunnelBundle) -> BTreeMap<String, IpAddr> {
    let mut map = BTreeMap::new();
    for peer in &bundle.peers {
        let Some(addr) = peer
            .allowed_ips
            .iter()
            .find_map(|cidr| parse_host_cidr_addr(cidr))
        else {
            continue;
        };
        map.entry(peer.node_id.as_str().to_owned()).or_insert(addr);
    }
    map
}

/// Parse a host CIDR (`a.b.c.d/32` or `x::y/128`) to its address.
/// Anything else — broader prefixes, malformed input — returns
/// `None` (fail-closed: better to omit an identity entry than to
/// invent one).
fn parse_host_cidr_addr(cidr: &str) -> Option<IpAddr> {
    let (addr_raw, prefix_raw) = cidr.trim().split_once('/')?;
    let addr: IpAddr = addr_raw.trim().parse().ok()?;
    let prefix: u8 = prefix_raw.trim().parse().ok()?;
    let host_prefix = match addr {
        IpAddr::V4(_) => 32,
        IpAddr::V6(_) => 128,
    };
    (prefix == host_prefix).then_some(addr)
}

