    #[test]
    fn load_auto_tunnel_bundle_rejects_sig_tamper_at_reload() {
        let test_dir = secure_test_dir("rustynetd-auto-sig-tamper-mismatch");
        let assignment_path = test_dir.join("assignment.bundle");
        let assignment_verifier_path = test_dir.join("assignment.verifier.pub");
        write_auto_tunnel_file(
            &assignment_path,
            &assignment_verifier_path,
            "daemon-local",
            8,
            false,
        );
        let envelope = load_auto_tunnel_bundle(
            &assignment_path,
            &assignment_verifier_path,
            300,
            TrustPolicy::default(),
            None,
        )
        .expect("first auto tunnel load should succeed");

        let raw = std::fs::read_to_string(&assignment_path)
            .expect("assignment bundle should remain readable");
        let tampered = raw
            .lines()
            .map(|line| {
                if let Some(signature_hex) = line.strip_prefix("signature=") {
                    let mut chars = signature_hex.chars().collect::<Vec<_>>();
                    let first = chars
                        .first_mut()
                        .expect("fixture signature hex must not be empty");
                    *first = if *first == '0' { '1' } else { '0' };
                    format!("signature={}", chars.into_iter().collect::<String>())
                } else {
                    line.to_owned()
                }
            })
            .collect::<Vec<_>>()
            .join("\n");
        std::fs::write(&assignment_path, format!("{tampered}\n"))
            .expect("tampered assignment bundle should be written");

        let err = load_auto_tunnel_bundle(
            &assignment_path,
            &assignment_verifier_path,
            300,
            TrustPolicy::default(),
            Some(envelope.watermark),
        )
        .expect_err("tampered signature must fail");

        assert!(matches!(
            err,
            super::AutoTunnelBootstrapError::SignatureInvalid
        ));
        let _ = std::fs::remove_dir_all(test_dir);
    }

