    #[test]
    fn parse_windows_egress_output_accepts_common_interface_names() {
        // Plain adapter names without spaces.
        assert_eq!(
            parse_windows_default_egress_interface_output("Ethernet", "rustynet0")
                .expect("simple Ethernet alias must be accepted"),
            "Ethernet"
        );
        // Adapters with spaces in their names — common in Windows when there are
        // multiple ports of the same type ("Ethernet 2") or Hyper-V adapters
        // ("vEthernet (Default Switch)").
        assert_eq!(
            parse_windows_default_egress_interface_output("Ethernet 2\r\n", "rustynet0")
                .expect("alias with space and trailing CRLF must be trimmed and accepted"),
            "Ethernet 2"
        );
        assert_eq!(
            parse_windows_default_egress_interface_output("Wi-Fi", "")
                .expect("Wi-Fi alias with empty tunnel must be accepted"),
            "Wi-Fi"
        );
    }

    #[test]
    fn parse_windows_egress_output_fails_closed_for_empty_or_invalid_output() {
        // Empty output means no non-tunnel default route exists.
        parse_windows_default_egress_interface_output("", "rustynet0")
            .expect_err("empty output must fail closed");
        parse_windows_default_egress_interface_output("  \r\n  ", "rustynet0")
            .expect_err("whitespace-only output must fail closed");

        // Control characters in the alias are not valid Windows interface names
        // and would corrupt log lines or format strings.
        parse_windows_default_egress_interface_output("eth\n0", "rustynet0")
            .expect_err("alias with newline must fail closed");
        parse_windows_default_egress_interface_output("eth\t0", "rustynet0")
            .expect_err("alias with tab must fail closed");

        // '=' would corrupt the key=value netsh argument format.
        parse_windows_default_egress_interface_output("interface=eth0", "rustynet0")
            .expect_err("alias containing '=' must fail closed");

        // Non-ASCII is not valid in standard Windows adapter names.
        parse_windows_default_egress_interface_output("Éthernetø", "rustynet0")
            .expect_err("non-ASCII alias must fail closed");

        // Excessively long aliases are invalid.
        parse_windows_default_egress_interface_output(&"x".repeat(65), "rustynet0")
            .expect_err("alias longer than 64 chars must fail closed");
    }

    #[test]
    fn parse_windows_egress_output_fails_closed_when_tunnel_is_best_default_route() {
        // If the WireGuard tunnel interface is the detected egress interface, the
        // daemon is likely restarting with stale tunnel routes from a previous
        // session.  We must fail closed rather than using the tunnel as the
        // physical egress for NAT and bypass routes.
        let err = parse_windows_default_egress_interface_output("rustynet0", "rustynet0")
            .expect_err("tunnel alias as best route must fail closed");
        assert!(
            err.contains("tunnel interface"),
            "error must identify this as a tunnel-interface problem: {err}"
        );

        // Case-insensitive comparison so "RustyNet0" and "rustynet0" match.
        parse_windows_default_egress_interface_output("RustyNet0", "rustynet0")
            .expect_err("case-variant tunnel alias must also fail closed");

        // An empty tunnel alias disables the tunnel-exclusion check; the alias is
        // then treated as a regular physical interface.
        parse_windows_default_egress_interface_output("rustynet0", "")
            .expect("empty tunnel alias must disable the exclusion check");
    }

    fn egress_adapter(
        friendly: &str,
        oper_status: u32,
        ipv4_metric: u32,
        has_gateway: bool,
    ) -> rustynet_windows_native::WindowsNetworkAdapterSnapshot {
        rustynet_windows_native::WindowsNetworkAdapterSnapshot {
            adapter_name: format!("{friendly}-name"),
            friendly_name: friendly.to_owned(),
            description: format!("{friendly} description"),
            if_index: 1,
            ipv6_if_index: 1,
            if_type: 6,
            oper_status,
            ipv4_metric,
            ipv6_metric: ipv4_metric,
            unicast_addresses: Vec::new(),
            default_gateways: if has_gateway {
                vec![std::net::IpAddr::V4(std::net::Ipv4Addr::new(
                    192, 168, 0, 1,
                ))]
            } else {
                Vec::new()
            },
        }
    }

    #[test]
    fn select_windows_egress_picks_lowest_metric_up_gateway_interface() {
        let high = egress_adapter("Ethernet", 1, 25, true);
        let low = egress_adapter("Wi-Fi", 1, 5, true);
        let tunnel = egress_adapter("rustynet0", 1, 1, true);
        let selected =
            super::select_windows_default_egress_interface(&[high, low, tunnel], "rustynet0")
                .expect("an egress interface");
        assert_eq!(selected, "Wi-Fi");
    }

    #[test]
    fn select_windows_egress_skips_down_and_gatewayless_interfaces() {
        let down = egress_adapter("Ethernet", 2, 1, true); // down, lowest metric -> skip
        let no_gateway = egress_adapter("Wi-Fi", 1, 2, false); // up, no gateway -> skip
        let usable = egress_adapter("Ethernet 2", 1, 30, true);
        let selected = super::select_windows_default_egress_interface(
            &[down, no_gateway, usable],
            "rustynet0",
        )
        .expect("an egress interface");
        assert_eq!(selected, "Ethernet 2");
    }

    #[test]
    fn select_windows_egress_errors_when_only_tunnel_has_default_gateway() {
        // A stale tunnel default route after a crash must not select the tunnel
        // as its own egress; with no other gateway interface this fails closed.
        let tunnel = egress_adapter("rustynet0", 1, 1, true);
        let down_phys = egress_adapter("Ethernet", 2, 5, true);
        let err = super::select_windows_default_egress_interface(&[tunnel, down_phys], "rustynet0")
            .expect_err("must not select the tunnel as its own egress");
        assert!(err.contains("no operational, non-tunnel interface"));
    }

    fn egress_adapter_with_ipv4(
        friendly: &str,
        oper_status: u32,
        ipv4_metric: u32,
        has_gateway: bool,
        ipv4: &[std::net::Ipv4Addr],
    ) -> rustynet_windows_native::WindowsNetworkAdapterSnapshot {
        let mut adapter = egress_adapter(friendly, oper_status, ipv4_metric, has_gateway);
        adapter.unicast_addresses = ipv4.iter().copied().map(std::net::IpAddr::V4).collect();
        adapter
    }

    #[test]
    fn select_windows_egress_falls_back_to_lan_interface_without_gateway() {
        // Same-LAN-only client: the only up, non-tunnel interface has a routable
        // IPv4 but no default gateway (an isolated subnet with no default route).
        // It must still be selectable as egress so the daemon can start.
        let lan =
            egress_adapter_with_ipv4("Ethernet", 1, 15, false, &[Ipv4Addr::new(192, 168, 0, 45)]);
        let tunnel = egress_adapter("rustynet0", 1, 1, false);
        let selected = super::select_windows_default_egress_interface(&[lan, tunnel], "rustynet0")
            .expect("the gateway-less LAN interface is a valid egress for a same-LAN client");
        assert_eq!(selected, "Ethernet");
    }

    #[test]
    fn select_windows_egress_prefers_gateway_over_lan_fallback() {
        // A real gateway interface always wins over a gateway-less fallback, even
        // when the fallback advertises a lower metric.
        let lan = egress_adapter_with_ipv4("Wi-Fi", 1, 5, false, &[Ipv4Addr::new(192, 168, 0, 45)]);
        let gateway =
            egress_adapter_with_ipv4("Ethernet", 1, 50, true, &[Ipv4Addr::new(10, 0, 0, 9)]);
        let selected = super::select_windows_default_egress_interface(&[lan, gateway], "rustynet0")
            .expect("an egress interface");
        assert_eq!(selected, "Ethernet");
    }

    #[test]
    fn select_windows_egress_fallback_picks_lowest_metric_lan_interface() {
        let high =
            egress_adapter_with_ipv4("Ethernet", 1, 40, false, &[Ipv4Addr::new(192, 168, 0, 45)]);
        let low = egress_adapter_with_ipv4(
            "Ethernet 2",
            1,
            10,
            false,
            &[Ipv4Addr::new(192, 168, 1, 45)],
        );
        let selected = super::select_windows_default_egress_interface(&[high, low], "rustynet0")
            .expect("an egress interface");
        assert_eq!(selected, "Ethernet 2");
    }

    #[test]
    fn select_windows_egress_fallback_rejects_loopback_and_link_local() {
        // Neither a loopback (127/8) nor an APIPA link-local (169.254/16) address
        // is a routable underlay; with no gateway and no routable IPv4 this fails
        // closed rather than picking a non-routable interface as egress.
        let loopbackish =
            egress_adapter_with_ipv4("Ethernet", 1, 10, false, &[Ipv4Addr::new(127, 0, 0, 1)]);
        let link_local =
            egress_adapter_with_ipv4("Wi-Fi", 1, 20, false, &[Ipv4Addr::new(169, 254, 3, 4)]);
        let err =
            super::select_windows_default_egress_interface(&[loopbackish, link_local], "rustynet0")
                .expect_err("a non-routable-only host has no valid egress");
        assert!(err.contains("no operational, non-tunnel interface"));
    }

