    #[test]
    fn daemon_runtime_authoritative_stun_refresh_uses_backend_shared_transport_identity() {
        let relay_addr: SocketAddr = "203.0.113.31:40021".parse().expect("relay addr");
        let (mut runtime, test_dir) = build_runtime_with_custom_relay(
            "rustynetd-runtime-authoritative-stun-shared-transport",
            relay_addr,
            "relay-eu-1",
        );
        let authoritative_local_addr: SocketAddr =
            "0.0.0.0:51820".parse().expect("local addr should parse");
        let stun_server: SocketAddr = "198.51.100.1:3478"
            .parse()
            .expect("stun server should parse");
        let mapped_endpoint: SocketAddr = "198.51.100.24:62000"
            .parse()
            .expect("mapped endpoint should parse");

        configure_runtime_authoritative_transport(&mut runtime, authoritative_local_addr);
        runtime.traversal_probe_config.stun_servers = vec![stun_server];
        runtime.next_stun_refresh_at = Some(Instant::now());
        runtime
            .controller
            .backend_mut_for_test()
            .script_authoritative_stun_round_trip_for_test(stun_server, mapped_endpoint)
            .expect("stun authoritative round trip should be scriptable");

        runtime.bootstrap();
        runtime.poll_stun_results();

        assert_eq!(runtime.local_stun_candidates, vec![mapped_endpoint]);
        assert_eq!(runtime.stun_candidate_local_addrs(), "0.0.0.0:51820");
        assert_eq!(
            runtime.transport_socket_identity_state(),
            "authoritative_backend_shared_transport"
        );
        let operations = runtime
            .controller
            .backend_mut_for_test()
            .authoritative_transport_operations_for_test();
        assert_eq!(operations.len(), 1);
        assert_eq!(
            operations[0].kind,
            RecordedAuthoritativeTransportOperationKind::RoundTrip
        );
        assert_eq!(operations[0].local_addr, authoritative_local_addr);
        assert_eq!(operations[0].remote_addr, stun_server);

        let netcheck = runtime.handle_command(IpcCommand::Netcheck);
        assert!(netcheck.ok);
        assert!(
            netcheck
                .message
                .contains("transport_socket_identity_state=authoritative_backend_shared_transport")
        );
        assert!(
            netcheck
                .message
                .contains("transport_socket_identity_local_addr=0.0.0.0:51820")
        );
        assert!(
            netcheck
                .message
                .contains("stun_candidates=198.51.100.24:62000")
        );
        assert!(
            netcheck
                .message
                .contains("stun_candidate_local_addrs=0.0.0.0:51820")
        );

        let _ = std::fs::remove_dir_all(test_dir);
    }

    /// Gap-2 regression: a detected local endpoint change must force the next
    /// STUN poll to re-gather immediately, collapsing the up-to-
    /// `DEFAULT_TRAVERSAL_STUN_GATHER_INTERVAL_SECS` wait so a moved srflx
    /// address drifts the CandidateSet and is broadcast within a reconcile
    /// tick. Without this, a peer whose public address changes can stay
    /// unreachable for up to a full gather interval after the NIC change is
    /// observed.
    #[test]
    fn endpoint_change_forces_immediate_stun_regather() {
        let relay_addr: SocketAddr = "203.0.113.33:40023".parse().expect("relay addr");
        let (mut runtime, test_dir) = build_runtime_with_custom_relay(
            "rustynetd-runtime-endpoint-change-forces-stun-regather",
            relay_addr,
            "relay-eu-1",
        );
        let authoritative_local_addr: SocketAddr =
            "0.0.0.0:51820".parse().expect("local addr should parse");
        configure_runtime_authoritative_transport(&mut runtime, authoritative_local_addr);

        // STUN active, but next refresh is scheduled far in the future
        // (simulating "gathered recently, not due for a while").
        let far_future = Instant::now() + Duration::from_secs(3_600);
        runtime.next_stun_refresh_at = Some(far_future);

        // Prime a stale fingerprint that differs from the current runtime
        // endpoint fingerprint so the change branch fires. No prior change
        // timestamp => the stability-window short-circuit is skipped.
        runtime.traversal_last_endpoint_fingerprint = Some("stale-endpoint-fingerprint".to_owned());
        runtime.traversal_last_endpoint_change_unix = None;

        runtime.maybe_trigger_endpoint_change_refresh();

        let next = runtime
            .next_stun_refresh_at
            .expect("STUN refresh must remain scheduled after an endpoint change");
        assert!(
            next <= Instant::now(),
            "endpoint change must force the next STUN re-gather to be due immediately"
        );
        assert!(
            next < far_future,
            "endpoint change must move the STUN refresh earlier than the prior schedule"
        );

        let _ = std::fs::remove_dir_all(test_dir);
    }

    /// Port-mapping lifecycle: a detected local endpoint change must force an
    /// immediate port-mapping re-bring_up (collapsing the wait to a reconcile
    /// tick) so a DHCP-reassigned internal IP gets a fresh router mapping
    /// instead of leaving the old mapping pointing at the stale address until
    /// its TTL lapses.
    #[test]
    fn endpoint_change_forces_immediate_port_mapping_release() {
        let relay_addr: SocketAddr = "203.0.113.34:40024".parse().expect("relay addr");
        let (mut runtime, test_dir) = build_runtime_with_custom_relay(
            "rustynetd-runtime-endpoint-change-forces-port-mapping",
            relay_addr,
            "relay-eu-1",
        );

        runtime.port_mapping_mode = crate::port_mapper::PortMappingMode::Auto;
        let far_future = Instant::now() + Duration::from_secs(3_600);
        runtime.next_port_mapping_refresh_at = Some(far_future);

        runtime.traversal_last_endpoint_fingerprint = Some("stale-endpoint-fingerprint".to_owned());
        runtime.traversal_last_endpoint_change_unix = None;

        runtime.maybe_trigger_endpoint_change_refresh();

        let next = runtime
            .next_port_mapping_refresh_at
            .expect("port-mapping refresh must remain scheduled after an endpoint change");
        assert!(
            next <= Instant::now(),
            "endpoint change must force the next port-mapping re-bring_up to be due immediately"
        );
        assert!(
            next < far_future,
            "endpoint change must move the port-mapping refresh earlier than the prior schedule"
        );

        let _ = std::fs::remove_dir_all(test_dir);
    }

    /// Port-mapping lifecycle: when this node is not the elected
    /// port-mapping authority (here: no membership state at all), a due
    /// refresh must NOT hold a lease and must reschedule a re-check rather
    /// than disarming — so authority swinging back to us is picked up
    /// without a restart. Exercises the authority-gating path with no
    /// network dependency.
    #[test]
    fn port_mapping_refresh_defers_when_not_authority() {
        let relay_addr: SocketAddr = "203.0.113.35:40025".parse().expect("relay addr");
        let (mut runtime, test_dir) = build_runtime_with_custom_relay(
            "rustynetd-runtime-port-mapping-not-authority",
            relay_addr,
            "relay-eu-1",
        );

        runtime.port_mapping_mode = crate::port_mapper::PortMappingMode::Auto;
        runtime.membership_state = None; // => skip_reason: authority unavailable
        runtime.port_mapping_lease = None;
        runtime.next_port_mapping_refresh_at = Some(Instant::now());

        runtime.maybe_refresh_port_mapping();

        assert!(
            runtime.port_mapping_lease.is_none(),
            "a non-authority node must not hold a port-mapping lease"
        );
        let next = runtime
            .next_port_mapping_refresh_at
            .expect("non-authority node must reschedule a re-check, not disarm refresh");
        assert!(
            next > Instant::now(),
            "the re-check must be scheduled in the future, not left immediately due"
        );

        let _ = std::fs::remove_dir_all(test_dir);
    }

    #[test]
    fn daemon_runtime_relay_establish_and_keepalive_use_backend_shared_transport_identity() {
        let relay_addr: SocketAddr = "203.0.113.32:40022".parse().expect("relay addr");
        let (mut runtime, test_dir) = build_runtime_with_custom_relay(
            "rustynetd-runtime-authoritative-relay-shared-transport",
            relay_addr,
            "relay-eu-1",
        );
        let authoritative_local_addr: SocketAddr =
            "0.0.0.0:51820".parse().expect("local addr should parse");
        let allocated_port = 61_044;
        let exit_node = NodeId::new("node-exit".to_owned()).expect("node id should parse");

        configure_runtime_authoritative_transport(&mut runtime, authoritative_local_addr);
        script_runtime_authoritative_relay_ack(
            &mut runtime,
            relay_addr,
            authoritative_local_addr,
            [0x44; 16],
            allocated_port,
        );
        runtime.relay_client = Some(build_test_relay_client(
            "daemon-local",
            Duration::from_millis(200),
            Duration::from_millis(50),
            Vec::new(),
        ));

        runtime.bootstrap();
        runtime
            .relay_client
            .as_mut()
            .expect("relay client should be configured")
            .set_session_last_activity_for_test(
                &exit_node,
                Instant::now() - Duration::from_secs(60),
            );
        runtime
            .controller
            .backend_mut_for_test()
            .script_authoritative_send_result_for_test(Ok(()))
            .expect("relay authoritative keepalive send should be scriptable");

        runtime
            .sync_traversal_runtime_state(false)
            .expect("relay runtime sync should succeed");

        let operations = runtime
            .controller
            .backend_mut_for_test()
            .authoritative_transport_operations_for_test();
        assert_eq!(operations.len(), 2);
        assert_eq!(
            operations[0].kind,
            RecordedAuthoritativeTransportOperationKind::RoundTrip
        );
        assert_eq!(operations[0].local_addr, authoritative_local_addr);
        assert_eq!(operations[0].remote_addr, relay_addr);
        assert_eq!(
            operations[1].kind,
            RecordedAuthoritativeTransportOperationKind::Send
        );
        assert_eq!(operations[1].local_addr, authoritative_local_addr);
        assert_eq!(
            operations[1].remote_addr,
            SocketAddr::new(relay_addr.ip(), allocated_port)
        );
        assert_eq!(
            runtime.controller.managed_peer_endpoint(&exit_node),
            Some(SocketEndpoint {
                addr: relay_addr.ip(),
                port: allocated_port,
            })
        );

        let status = runtime.handle_command(IpcCommand::Status);
        assert!(status.ok);
        assert!(
            status
                .message
                .contains("transport_socket_identity_state=authoritative_backend_shared_transport")
        );
        assert!(
            status
                .message
                .contains("transport_socket_identity_local_addr=0.0.0.0:51820")
        );

        let _ = std::fs::remove_dir_all(test_dir);
    }

